use std::f64::consts::PI;
use std::fmt;

#[derive(Debug, Clone)]
enum Shape {
    Circle { cx: f64, cy: f64, radius: f64 },
    Rectangle { x: f64, y: f64, width: f64, height: f64 },
    Triangle { ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64 },
}

impl Shape {
    fn area(&self) -> f64 {
        match self {
            Shape::Circle { radius, .. }       => PI * radius * radius,
            Shape::Rectangle { width, height, .. } => width * height,
            Shape::Triangle { ax, ay, bx, by, cx, cy } => {
                // Shoelace formula
                ((ax * (by - cy) + bx * (cy - ay) + cx * (ay - by)) / 2.0).abs()
            }
        }
    }

    fn perimeter(&self) -> f64 {
        match self {
            Shape::Circle { radius, .. } => 2.0 * PI * radius,
            Shape::Rectangle { width, height, .. } => 2.0 * (width + height),
            Shape::Triangle { ax, ay, bx, by, cx, cy } => {
                let d = |x1: f64, y1: f64, x2: f64, y2: f64| ((x2-x1).powi(2)+(y2-y1).powi(2)).sqrt();
                d(*ax,*ay,*bx,*by) + d(*bx,*by,*cx,*cy) + d(*cx,*cy,*ax,*ay)
            }
        }
    }
}

impl fmt::Display for Shape {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "area={:.2} perimeter={:.2}", self.area(), self.perimeter())
    }
}

