impl<T: Clone> Tree<T> {
    fn depth(&self) -> usize {
        match self {
            Tree::Leaf(_) => 0,
            Tree::Branch(children) => {
                1 + children.iter().map(|c| c.depth()).max().unwrap_or(0)
            }
        }
    }

    fn leaves(&self) -> Vec<&T> {
        match self {
            Tree::Leaf(v) => vec![v],
            Tree::Branch(children) => {
                children.iter().flat_map(|c| c.leaves()).collect()
            }
        }
    }

    fn count_nodes(&self) -> usize {
        match self {
            Tree::Leaf(_) => 1,
            Tree::Branch(ch) => 1 + ch.iter().map(|c| c.count_nodes()).sum::<usize>(),
        }
    }
}

