#[derive(Debug)]
enum Bst {
    Empty,
    Node { val: i32, left: Box<Bst>, right: Box<Bst> },
}

impl Bst {
    fn empty() -> Self { Bst::Empty }

    fn insert(self, new_val: i32) -> Self {
        match self {
            Bst::Empty => Bst::Node {
                val: new_val,
                left: Box::new(Bst::Empty),
                right: Box::new(Bst::Empty),
            },
            Bst::Node { val, left, right } => {
                if new_val < val {
                    Bst::Node { val, left: Box::new(left.insert(new_val)), right }
                } else if new_val > val {
                    Bst::Node { val, left, right: Box::new(right.insert(new_val)) }
                } else {
                    Bst::Node { val, left, right } // duplicate — ignore
                }
            }
        }
    }

    fn contains(&self, target: i32) -> bool {
        match self {
            Bst::Empty => false,
            Bst::Node { val, left, right } => {
                if target == *val { true }
                else if target < *val { left.contains(target) }
                else { right.contains(target) }
            }
        }
    }

    fn sorted_vec(&self) -> Vec<i32> {
        match self {
            Bst::Empty => vec![],
            Bst::Node { val, left, right } => {
                let mut v = left.sorted_vec();
                v.push(*val);
                v.extend(right.sorted_vec());
                v
            }
        }
    }
}

fn main() {
    let tree = [5, 3, 7, 1, 4, 6, 8].iter()
        .fold(Bst::empty(), |t, &v| t.insert(v));
    println!("{:?}", tree.sorted_vec());
    println!("has 4: {} has 9: {}", tree.contains(4), tree.contains(9));
