use std::fmt;

#[derive(Debug, Clone)]
enum Ast {
    Lit(i64),
    BinOp { op: char, l: Box<Ast>, r: Box<Ast> },
    UnOp  { op: char, e: Box<Ast> },
}

impl Ast {
    fn precedence(&self) -> u8 {
        match self {
            Ast::Lit(_)            => 10,
            Ast::UnOp { .. }       => 8,
            Ast::BinOp { op, .. }  => match op { '*' | '/' => 6, _ => 4 },
        }
    }

    fn fmt_with_parens(&self, parent_prec: u8, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let my_prec = self.precedence();
        if my_prec < parent_prec { write!(f, "(")?; }
        match self {
            Ast::Lit(n) => write!(f, "{}", n)?,
            Ast::UnOp { op, e } => {
                write!(f, "{}", op)?;
                e.fmt_with_parens(my_prec + 1, f)?;
            }
            Ast::BinOp { op, l, r } => {
                l.fmt_with_parens(my_prec, f)?;
                write!(f, " {} ", op)?;
                r.fmt_with_parens(my_prec + 1, f)?;
            }
        }
        if my_prec < parent_prec { write!(f, ")")? }
        Ok(())
    }

    fn eval(&self) -> Option<i64> {
        match self {
            Ast::Lit(n) => Some(*n),
            Ast::UnOp { op: '-', e } => Some(-e.eval()?),
            Ast::BinOp { op, l, r } => {
                let (lv, rv) = (l.eval()?, r.eval()?);
                match op {
                    '+' => Some(lv + rv), '-' => Some(lv - rv),
                    '*' => Some(lv * rv), '/' => (rv != 0).then(|| lv / rv),
                    _ => None,
                }
            }
            _ => None,
        }
    }
}

impl fmt::Display for Ast {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        self.fmt_with_parens(0, f)
    }
}

fn main() {
    let e = Ast::BinOp {
        op: '*',
        l: Box::new(Ast::BinOp { op: '+', l: Box::new(Ast::Lit(1)), r: Box::new(Ast::Lit(2)) }),
        r: Box::new(Ast::Lit(3)),
    };
    println!("{} = {:?}", e, e.eval());
