    pc: usize,
}

#[derive(Debug)]
enum VmError { StackUnderflow, EmptyStack }

impl std::fmt::Display for VmError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self { VmError::StackUnderflow => write!(f, "stack underflow"), VmError::EmptyStack => write!(f, "empty stack") }
    }
}

impl Vm {
    fn new() -> Self { Vm { stack: Vec::new(), pc: 0 } }

    fn pop(&mut self) -> Result<i64, VmError> {
        self.stack.pop().ok_or(VmError::StackUnderflow)
    }

    fn execute(&mut self, program: &[Instruction]) -> Result<(), VmError> {
        while self.pc < program.len() {
            match &program[self.pc] {
                Instruction::Push(n)  => self.stack.push(*n),
                Instruction::Pop      => { self.pop()?; }
                Instruction::Add      => { let (a, b) = (self.pop()?, self.pop()?); self.stack.push(a + b); }
                Instruction::Sub      => { let (a, b) = (self.pop()?, self.pop()?); self.stack.push(b - a); }
                Instruction::Mul      => { let (a, b) = (self.pop()?, self.pop()?); self.stack.push(a * b); }
                Instruction::Dup      => { let top = *self.stack.last().ok_or(VmError::EmptyStack)?; self.stack.push(top); }
                Instruction::Swap     => { let (a, b) = (self.pop()?, self.pop()?); self.stack.push(a); self.stack.push(b); }
                Instruction::Print    => println!("{:?}", self.stack.last().ok_or(VmError::EmptyStack)?),
                Instruction::JumpIfZero(label) => {
                    if self.pop()? == 0 { self.pc = *label; continue; }
                }
            }
            self.pc += 1;
        }
        Ok(())
    }
}

