#[derive(Debug, Clone)]
struct Rose<T> {
    value: T,
    children: Vec<Rose<T>>,
}

impl<T: Clone> Rose<T> {
    fn leaf(value: T) -> Self { Rose { value, children: vec![] } }

    fn node(value: T, children: Vec<Rose<T>>) -> Self { Rose { value, children } }

    // Catamorphism (fold / cata): replaces each Rose node with f applied to the
    // node's value and the already-folded results of all children.
    fn fold<B, F: Fn(T, Vec<B>) -> B>(&self, f: &F) -> B {
        let folded_children: Vec<B> = self.children.iter().map(|c| c.fold(f)).collect();
        f(self.value.clone(), folded_children)
    }

    fn depth(&self) -> usize {
        self.fold(&|_, child_depths: Vec<usize>| {
            1 + child_depths.into_iter().max().unwrap_or(0)
        })
    }

    fn map<U: Clone, F: Fn(&T) -> U>(&self, f: &F) -> Rose<U> {
        Rose {
            value: f(&self.value),
            children: self.children.iter().map(|c| c.map(f)).collect(),
