#[derive(Debug, PartialEq)]
struct ParseError<'a> {
    input: &'a str,
    expected: &'static str,
}

type ParseResult<'a, T> = Result<(T, &'a str), ParseError<'a>>;

fn digits(input: &str) -> ParseResult<&str> {
    let end = input.find(|c: char| !c.is_ascii_digit()).unwrap_or(input.len());
    if end == 0 {
        Err(ParseError { input, expected: "digit" })
    } else {
        Ok((&input[..end], &input[end..]))
    }
}

fn alpha(input: &str) -> ParseResult<&str> {
    let end = input.find(|c: char| !c.is_alphabetic()).unwrap_or(input.len());
    if end == 0 {
        Err(ParseError { input, expected: "letter" })
    } else {
        Ok((&input[..end], &input[end..]))
    }
}

fn tag<'a>(expected: &'static str, input: &'a str) -> ParseResult<'a, &'a str> {
    if input.starts_with(expected) {
        Ok((&input[..expected.len()], &input[expected.len()..]))
    } else {
        Err(ParseError { input, expected })
    }
}

// Combinator: sequence two parsers
fn pair<'a, A, B, F, G>(f: F, g: G, input: &'a str) -> ParseResult<'a, (A, B)>
where
    F: Fn(&'a str) -> ParseResult<'a, A>,
    G: Fn(&'a str) -> ParseResult<'a, B>,
{
    let (a, rest) = f(input)?;
    let (b, rest) = g(rest)?;
    Ok(((a, b), rest))
}

fn main() {
    println!("{:?}", digits("123abc"));
    println!("{:?}", digits("abc"));
    println!("{:?}", tag("fn", "fn foo()"));

    // Compose parsers with pair:
    let result = pair(alpha, |s| tag("=", s), "x=42");
    println!("{:?}", result);
}

