// #[non_exhaustive] on an enum forces downstream users to have a wildcard arm
// (useful for library enums that may grow)
#[non_exhaustive]
#[derive(Debug)]
pub enum Status {
    Active,
    Inactive,
    Pending,
    Archived,
}

pub fn describe(s: &Status) -> &str {
    match s {
        Status::Active   => "active",
        Status::Inactive => "inactive",
        Status::Pending  => "pending",
        Status::Archived => "archived",
        // Downstream crates must have `_ => ...` because of #[non_exhaustive]:
        #[allow(unreachable_patterns)]
        _ => "unknown",
    }
}

// Within the defining crate, you can still match exhaustively:
fn is_visible(s: &Status) -> bool {
    matches!(s, Status::Active | Status::Pending)
}

fn main() {
    for s in [Status::Active, Status::Inactive, Status::Pending, Status::Archived] {
        println!("{:?} -> {} visible={}", s, describe(&s), is_visible(&s));
    }
}

