use std::collections::VecDeque;

#[derive(Debug, Clone)]
struct ListZipper<T> {
    left:  Vec<T>,     // elements to the left (in reverse order)
    focus: T,
    right: VecDeque<T>, // elements to the right
}

#[derive(Debug)]
enum ZipperResult<T> {
    Moved(ListZipper<T>),
    AtEnd(ListZipper<T>),
}

impl<T: Clone> ListZipper<T> {
    fn new(head: T, rest: impl IntoIterator<Item = T>) -> Self {
        ListZipper { left: Vec::new(), focus: head, right: rest.into_iter().collect() }
    }

    fn move_right(mut self) -> ZipperResult<T> {
        if let Some(next) = self.right.pop_front() {
            self.left.push(self.focus);
            self.focus = next;
            ZipperResult::Moved(self)
        } else {
            ZipperResult::AtEnd(self)
        }
    }

    fn move_left(mut self) -> ZipperResult<T> {
        if let Some(prev) = self.left.pop() {
            self.right.push_front(self.focus);
            self.focus = prev;
            ZipperResult::Moved(self)
        } else {
            ZipperResult::AtEnd(self)
        }
    }

    fn set_focus(mut self, val: T) -> Self {
        self.focus = val; self
    }

    fn to_vec(mut self) -> Vec<T> {
        let mut v: Vec<T> = self.left.into_iter().rev().collect();
        v.push(self.focus);
        v.extend(self.right);
        v
    }
}

fn main() {
    let z = ListZipper::new(1i32, [2, 3, 4, 5]);
    let z = match z.move_right() { ZipperResult::Moved(z) => z, ZipperResult::AtEnd(z) => z };
    let z = match z.move_right() { ZipperResult::Moved(z) => z, ZipperResult::AtEnd(z) => z };
    let z = z.set_focus(99);
    println!("{:?}", z.to_vec()); // [1, 2, 99, 4, 5]
}
